export const setupNetworkInterceptor = (axiosInstance) => {
  axiosInstance.interceptors.request.use(
    (config) => {
      config.metadata = { startTime: Date.now() };
      logger.logNetworkRequest(config);
      return config;
    },
    (error) => {
      logger.logNetworkError(error);
      return Promise.reject(error);
    }
  );

  axiosInstance.interceptors.response.use(
    (response) => {
      response.duration = Date.now() - response.config.metadata.startTime;
      logger.logNetworkResponse(response);
      return response;
    },
    (error) => {
      logger.logNetworkError(error);
      return Promise.reject(error);
    }
  );
};

